 const int force_vert_split = ( mi_col + ms >= cm -> mi_cols ) ;
 const int xss = x -> e_mbd . plane [ 1 ] . subsampling_x ;
 const int yss = x -> e_mbd . plane [ 1 ] . subsampling_y ;
 int partition_none_allowed = ! force_horz_split && ! force_vert_split ;
