 store_pred_mv ( x , ctx ) ;
 sum_rd = 0 ;
 if ( do_split ) {
 int pl = partition_plane_context ( xd , mi_row , mi_col , bsize ) ;
 sum_rate += cpi -> partition_cost [ pl ] [ PARTITION_SPLIT ] ;
 subsize = get_subsize ( bsize , PARTITION_SPLIT ) ;
 for ( i = 0 ;
 i < 4 && sum_rd < best_rd ;
 ++ i ) {
 const int x_idx = ( i & 1 ) * ms ;
