 locked = 0 ;
 }
 kadm5_destroy ( handle ) ;
 if ( ccache_name != NULL ) {
 fprintf ( stderr , "\n\a\a\a%s" , _ ( "Administration credentials NOT DESTROYED.\n" ) ) ;
