 for ( tmp = list ;
 tmp != NULL ;
 tmp = tmp -> next ) {
 window = tmp -> data ;
 window -> first_line += top ;
 mainwindow_resize ( window , 0 , - top ) ;
 }
 g_slist_free ( list ) ;
 }
 if ( bottom != 0 ) {
 GSList * list , * tmp ;
 g_return_val_if_fail ( bottom > 0 || screen_reserved_bottom > bottom , - 1 ) ;
