 list = mainwindows_get_line ( mainwindows_find_upper ( NULL ) ) ;
 for ( tmp = list ;
 tmp != NULL ;
 tmp = tmp -> next ) {
 window = tmp -> data ;
 window -> last_line -= bottom ;
 mainwindow_resize ( window , 0 , - bottom ) ;
 }
 g_slist_free ( list ) ;
 }
