 break ;
 case 2 : * left = & h -> left_border_y [ 8 ] ;
 memcpy ( & top [ 1 ] , h -> cy + 7 * h -> l_stride , 16 ) ;
 top [ 17 ] = top [ 16 ] ;
 top [ 0 ] = top [ 1 ] ;
 if ( h -> flags & A_AVAIL ) top [ 0 ] = h -> left_border_y [ 8 ] ;
