 ctx -> D [ 2 ] = Y [ 3 + Ystride * 2 ] - Y [ 3 + Ystride ] ;
 ctx -> D [ 3 ] = Y [ 3 + Ystride * 3 ] - Y [ 3 + Ystride * 2 ] ;
