 else {
 event_debug ( ( "%s: bad version %s on request %p from %s" , __func__ , version , req , req -> remote_host ) ) ;
 return ( - 1 ) ;
 }
 if ( ( req -> uri = strdup ( uri ) ) == NULL ) {
 event_debug ( ( "%s: evhttp_decode_uri" , __func__ ) ) ;
 return ( - 1 ) ;
