 return - 1 ;
 }
 if ( code == 0 ) {
 level = 0 ;
 }
 else {
 if ( IS_3IV1 ) {
 if ( code == 1 ) level = 2 * get_bits1 ( & s -> gb ) - 1 ;
 else {
 if ( get_bits1 ( & s -> gb ) ) level = get_bits ( & s -> gb , code - 1 ) + ( 1 << ( code - 1 ) ) ;
