 }
 }
 else {
 level = get_xbits ( & s -> gb , code ) ;
 }
 if ( code > 8 ) {
 if ( get_bits1 ( & s -> gb ) == 0 ) {
 if ( s -> err_recognition & AV_EF_BITSTREAM ) {
 av_log ( s -> avctx , AV_LOG_ERROR , "dc marker bit missing\n" ) ;
 return - 1 ;
 }
 }
 }
