static void test_multiplesignal ( void ) {
 struct event ev_one , ev_two ;
 struct itimerval itv ;
 setup_test ( "Multiple signal: " ) ;
 signal_set ( & ev_one , SIGALRM , signal_cb , & ev_one ) ;
 signal_add ( & ev_one , NULL ) ;
 signal_set ( & ev_two , SIGALRM , signal_cb , & ev_two ) ;
 signal_add ( & ev_two , NULL ) ;
 memset ( & itv , 0 , sizeof ( itv ) ) ;
 itv . it_value . tv_sec = 1 ;
 if ( setitimer ( ITIMER_REAL , & itv , NULL ) == - 1 ) goto skip_simplesignal ;
 event_dispatch ( ) ;
 skip_simplesignal : if ( signal_del ( & ev_one ) == - 1 ) test_ok = 0 ;
 if ( signal_del ( & ev_two ) == - 1 ) test_ok = 0 ;
 cleanup_test ( ) ;
 },0

int ReconnectToServer ( ArchiveHandle * AH , const char * dbname , const char * username ) {
 PGconn * newConn ;
 const char * newdbname ;
 const char * newusername ;
 if ( ! dbname ) newdbname = PQdb ( AH -> connection ) ;
 else newdbname = dbname ;
 if ( ! username ) newusername = PQuser ( AH -> connection ) ;
 else newusername = username ;
 if ( strcmp ( newdbname , PQdb ( AH -> connection ) ) == 0 && strcmp ( newusername , PQuser ( AH -> connection ) ) == 0 ) return 1 ;
 newConn = _connectDB ( AH , newdbname , newusername ) ;
 set_archive_cancel_info ( AH , newConn ) ;
 PQfinish ( AH -> connection ) ;
 AH -> connection = newConn ;
 return 1 ;
 },0

