 else if ( controller -> type == VIR_DOMAIN_CONTROLLER_TYPE_USB ) {
 if ( controller -> idx == 0 ) return VIR_STRDUP ( controller -> info . alias , "usb" ) ;
 }
 return virAsprintf ( & controller -> info . alias , "%s%d" , prefix , controller -> idx ) ;
